"use client";

import { ChangeEvent, FormEvent, useEffect, useMemo, useState } from "react";
import Link from "next/link";

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

type MediaItem = {
  id: string;
  type: string;
  title: string;
  description: string;
  fileUrl: string;
  mimeType: string;
  createdAt: string;
  votesCount: number;
  avgRating: number;
};

type MediaVoteResp = {
  submissionId: string;
  votesCount: number;
  avgRating: number;
  myRating: number;
};

function renderRatingStars(avgRating: number) {
  const clamped = Math.max(0, Math.min(5, avgRating || 0));
  const full = Math.floor(clamped);
  const half = clamped - full >= 0.5;
  const empty = 5 - full - (half ? 1 : 0);

  // ASCII-only representation to keep output portable.
  return "*".repeat(full) + (half ? "+" : "") + ".".repeat(empty);
}

export default function AiCinemaPage() {
  const [token, setToken] = useState<string>("");
  const [items, setItems] = useState<MediaItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState<string | null>(null);

  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [fileDataUrl, setFileDataUrl] = useState<string>("");
  const [fileMimeType, setFileMimeType] = useState<string>("");
  const [fileName, setFileName] = useState<string>("");
  const [submitting, setSubmitting] = useState(false);

  const canUpload = useMemo(() => {
    return Boolean(title.trim() && description.trim() && fileDataUrl);
  }, [title, description, fileDataUrl]);

  useEffect(() => {
    const t = localStorage.getItem("aevion_token") || "";
    setToken(t);
  }, []);

  const load = async () => {
    try {
      setErr(null);
      setLoading(true);
      const res = await fetch(`${API_BASE}/api/media/submissions?type=cinema`);
      const data = await res.json();
      if (!res.ok) throw new Error(data?.error || "Не удалось загрузить список");
      setItems((data?.items || []) as MediaItem[]);
    } catch (e: any) {
      setErr(e?.message || "Ошибка загрузки");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const onFile = async (e: ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (!f) return;

    setFileName(f.name);
    setFileMimeType(f.type || "application/octet-stream");
    setFileDataUrl("");

    const reader = new FileReader();
    const p = new Promise<void>((resolve, reject) => {
      reader.onloadend = () => resolve();
      reader.onerror = () => reject(new Error("Не удалось прочитать файл"));
    });
    reader.readAsDataURL(f);
    await p;
    const result = reader.result;
    if (typeof result === "string") setFileDataUrl(result);
  };

  const upload = async (e: FormEvent) => {
    e.preventDefault();
    if (!token) {
      setErr("Нужно войти, чтобы загрузить кино и получать права автора.");
      return;
    }
    if (!canUpload || submitting) return;

    setSubmitting(true);
    setErr(null);

    try {
      const res = await fetch(`${API_BASE}/api/media/submissions`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          type: "cinema",
          title: title.trim(),
          description: description.trim(),
          file: {
            fileName,
            mimeType: fileMimeType || "application/octet-stream",
            dataUrl: fileDataUrl,
          },
        }),
      });

      const data = await res.json().catch(() => null);
      if (!res.ok) throw new Error(data?.error || data?.details || "Ошибка upload");

      setTitle("");
      setDescription("");
      setFileDataUrl("");
      setFileMimeType("");
      setFileName("");

      await load();
    } catch (e: any) {
      setErr(e?.message || "Ошибка загрузки");
    } finally {
      setSubmitting(false);
    }
  };

  const vote = async (id: string, rating: number) => {
    if (!token) {
      setErr("Чтобы голосовать, нужно войти в `Auth`.");
      return;
    }

    const res = await fetch(`${API_BASE}/api/media/submissions/${id}/vote`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ rating }),
    });

    const data: MediaVoteResp | null = await res.json().catch(() => null);
    if (!res.ok) throw new Error((data as any)?.error || "Ошибка голосования");
    await load();
  };

  return (
    <main style={{ padding: 24, maxWidth: 980 }}>
      <div style={{ display: "flex", justifyContent: "space-between", gap: 12 }}>
        <div>
          <h1 style={{ fontSize: 26, marginBottom: 6 }}>AI Cinema</h1>
          <p style={{ color: "#666", marginTop: 0 }}>
            Загрузка AI-кино и всемирное голосование 1..5.
          </p>
        </div>
        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
          <Link href="/" style={{ color: "#0a5" }}>
            Globus
          </Link>
          <Link href="/auth" style={{ color: "#0a5" }}>
            Auth
          </Link>
        </div>
      </div>

      <section
        style={{
          border: "1px solid #ddd",
          borderRadius: 12,
          padding: 14,
          marginTop: 18,
        }}
      >
        <h2 style={{ fontSize: 18, marginBottom: 10 }}>Загрузить кино</h2>

        {err && <div style={{ color: "crimson", marginBottom: 12 }}>{err}</div>}

        <form onSubmit={upload} style={{ display: "grid", gap: 10 }}>
          <input
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Название фильма/сцены"
            style={{
              padding: 10,
              borderRadius: 8,
              border: "1px solid #ccc",
            }}
          />

          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Описание / идея / что именно создано"
            rows={4}
            style={{
              padding: 10,
              borderRadius: 8,
              border: "1px solid #ccc",
              fontFamily: "monospace",
            }}
          />

          <input
            type="file"
            accept="video/*"
            onChange={onFile}
            style={{ padding: 6 }}
          />

          <div style={{ color: "#666", fontSize: 13 }}>
            {fileName ? (
              <span>
                Выбрано: <b>{fileName}</b>
              </span>
            ) : (
              "Файл не выбран"
            )}
          </div>

          <button
            type="submit"
            disabled={!token || !canUpload || submitting}
            style={{
              padding: 10,
              borderRadius: 8,
              border: "1px solid #111",
              background: !token || !canUpload ? "#888" : "#111",
              color: "#fff",
              width: 240,
            }}
          >
            {submitting ? "Загрузка..." : token ? "Отправить" : "Войти чтобы загрузить"}
          </button>
        </form>
      </section>

      <section style={{ marginTop: 18 }}>
        <h2 style={{ fontSize: 18, marginBottom: 10 }}>Топ работ (кино)</h2>

        {loading ? (
          <div style={{ color: "#666" }}>Загружаем...</div>
        ) : items.length === 0 ? (
          <div style={{ color: "#666" }}>Пока нет загруженных работ.</div>
        ) : (
          <div style={{ display: "grid", gap: 14 }}>
            {items.map((it) => {
              const src = `${API_BASE}${it.fileUrl}`;
              const isVideo = it.mimeType?.startsWith("video/");

              return (
                <article
                  key={it.id}
                  style={{
                    border: "1px solid #ddd",
                    borderRadius: 12,
                    padding: 14,
                  }}
                >
                  <div style={{ display: "flex", justifyContent: "space-between", gap: 10 }}>
                    <div>
                      <div style={{ fontWeight: 800, fontSize: 16 }}>{it.title}</div>
                      <div style={{ color: "#666", fontSize: 13, marginTop: 4 }}>
                        {new Date(it.createdAt).toLocaleString()}
                      </div>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <div style={{ fontWeight: 800 }}>
                        {it.avgRating.toFixed(2)} / 5
                      </div>
                      <div style={{ color: "#666", fontSize: 13 }}>
                        {it.votesCount} голос(ов)
                      </div>
                    </div>
                  </div>

                  <div style={{ marginTop: 12, color: "#333", lineHeight: 1.4 }}>
                    <div style={{ fontFamily: "monospace", whiteSpace: "pre-wrap" }}>
                      {it.description}
                    </div>
                  </div>

                  <div style={{ marginTop: 12 }}>
                    {isVideo ? (
                      <video
                        controls
                        src={src}
                        style={{ width: "100%", maxHeight: 360, borderRadius: 10 }}
                      />
                    ) : (
                      <audio controls src={src} style={{ width: "100%" }} />
                    )}
                  </div>

                  <div style={{ marginTop: 12, display: "flex", gap: 8, flexWrap: "wrap" }}>
                    {[1, 2, 3, 4, 5].map((r) => (
                      <button
                        key={r}
                        type="button"
                        onClick={() => vote(it.id, r)}
                        style={{
                          padding: "6px 10px",
                          borderRadius: 10,
                          border: "1px solid #111",
                          background: token ? "#111" : "#888",
                          color: "#fff",
                          opacity: token ? 1 : 0.7,
                        }}
                      >
                        {r}
                      </button>
                    ))}
                  </div>

                  <div style={{ color: "#666", fontSize: 13, marginTop: 10 }}>
                    Средняя оценка: <b>{renderRatingStars(it.avgRating)}</b>
                  </div>
                </article>
              );
            })}
          </div>
        )}
      </section>
    </main>
  );
}

